mapper.select:
SELECT trader_user.NAME name,party.user_name username,party.user_code user_code,party.role_name rolename, trader_user.UUID id,trader_user.PROFIT profit ,trader_user.AMOUNT_SUM amount_sum, DATE_FORMAT(trader_user.CREATE_TIME, '%Y-%m-%d %H:%i:%S') create_time FROM T_TRADER_USER trader_user LEFT JOIN TZ_USER party ON party.user_id = trader_user.PARTY_ID WHERE 1 = 1
AND T_TRADER_USER.NAME =#{name}
AND (party.user_name like CONCAT('%',#{username},'%') OR party.user_code like CONCAT('%',#{username},'%'))
ORDER BY trader_user.CREATE_TIME DESC LIMIT #{pageNo}, #{pageSize}
